var MY_DISTRICTS = ["edmonton-strathcona"]; // the example signed-in resident's home riding(s)
function postDistricts(p) { return p.districts || []; }
function inMyDistricts(p) { return postDistricts(p).some(function (s) { return MY_DISTRICTS.indexOf(s) >= 0; }); }
// an author "in my district": only meaningful when *I'm* residency-verified (kyc >= 2). Accepts the
// card shape (p.districts slugs) and the single-post shape (p.district display string). Drives the
// map-pin-house glyph for residency-verified neighbours (see tierIcon).
function authorDistrictSlugs(p) {
