// Official (3). `state.myDistricts` is the remembered intent; effectiveMyDistricts() is what
// actually filters — it disengages (without forgetting the intent) whenever districts aren't
// inferable or the account itself isn't residency-verified. Used by the feed matcher AND comments.
function districtsInferable() { return state.verified >= 2; }
function effectiveMyDistricts() { return state.myDistricts && state.kyc >= 2 && districtsInferable(); }
// a record/comment names a district that isn't mine (district-less ones — e.g. officials — are kept)
function outsideMyDistricts(p) { return (p.districts || []).length > 0 && !inMyDistricts(p); }
// Affected filter — a post qualifies when it names more than one district (multi-district) or
