function postQualifiesForAffected(p) { var ds = postDistricts(p); return ds.length === 0 || ds.length > 1; }
// same remembered-intent/disengage-without-forgetting coupling as effectiveMyDistricts, PLUS
// viewHasAffected(): Affected only ever applies to the ONE open post it was engaged on, so a
